SCRATCH="/tmp/claude-1000/-home-janfr-dev-pc-switcher/eebf8232-0dc0-48a6-a064-08a64fa3cdb1/scratchpad"
echo "===== activeHooks summary (capId / kind / ref / when / check) ====="
node -e '
const o = JSON.parse(require("fs").readFileSync(process.argv[1],"utf8"));
const hooks = o.activeHooks || o.hooks || [];
if (!Array.isArray(hooks)) { console.log("activeHooks not array; top keys:", Object.keys(o)); process.exit(0); }
console.log("count:", hooks.length);
for (const h of hooks) {
  console.log("---");
  console.log("capId:", h.capId, "| kind:", h.kind, "| blocking:", h.blocking, "| into:", h.into);
  if (h.ref) console.log("  ref:", JSON.stringify(h.ref));
  if (h.check) console.log("  check:", JSON.stringify(h.check));
  if (h.when) console.log("  when:", JSON.stringify(h.when));
  if (h.configValues) console.log("  configValues:", JSON.stringify(h.configValues));
  if (h.fragment) console.log("  fragment.inline length:", (h.fragment.inline||"").length);
}
' "$SCRATCH/plan-pre-hooks.json"

